import { Transport } from '@wince/transport';
import type { DropReason } from '@wince/transport';

export interface ClientTransportOptions {
  url: string;
  compress?: boolean;
  batchSize?: number;
  batchTimeoutMs?: number;
  maxBufferSize?: number;
  headers?: Record<string, string>;
  retry?: unknown;
  fetch?: (url: string, init: RequestInit) => Promise<Response>;
  paused?: boolean;
  onDropped?: (reason: DropReason, item?: Record<string, unknown>) => void;
  onBatchDelivered?: (eids: string[]) => void;
  eventPriority?: (event: Record<string, unknown>) => number;
}

export function createClientTransport(opts: ClientTransportOptions): Transport {
  return new Transport({
    url: opts.url,
    compress: opts.compress ?? true,
    batchSize: opts.batchSize ?? 20,
    batchTimeoutMs: opts.batchTimeoutMs ?? 2_000,
    maxBufferSize: opts.maxBufferSize ?? 500,
    headers: opts.headers,
    retry: opts.retry as any,
    fetch: opts.fetch,
    paused: opts.paused ?? true,
    onDropped: opts.onDropped,
    onBatchDelivered: opts.onBatchDelivered,
    eventPriority: opts.eventPriority,
  });
}
